-- Enable pgvector extension (used by Incident.embedding / Postmortem.embedding vector(1536))
-- 必须先于 CREATE TABLE incidents/postmortems 执行，否则 vector 类型不存在
CREATE EXTENSION IF NOT EXISTS vector;

-- Create "action_items" table
CREATE TABLE "action_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "description" text NOT NULL,
  "owner_id" character varying NULL,
  "due_date" timestamptz NULL,
  "status" character varying NOT NULL DEFAULT 'open',
  "tracker_url" character varying NULL,
  "external_id" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "postmortem_action_items" bigint NULL,
  PRIMARY KEY ("id")
);
-- Create index "actionitem_due_date" to table: "action_items"
CREATE INDEX "actionitem_due_date" ON "action_items" ("due_date");
-- Create index "actionitem_external_id" to table: "action_items"
CREATE INDEX "actionitem_external_id" ON "action_items" ("external_id");
-- Create index "actionitem_status" to table: "action_items"
CREATE INDEX "actionitem_status" ON "action_items" ("status");
-- Create "ai_insights" table
CREATE TABLE "ai_insights" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "stage" character varying NOT NULL,
