  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "incident_ai_insights" bigint NULL,
  PRIMARY KEY ("id")
);
-- Create index "aiinsight_incident_ai_insights" to table: "ai_insights"
CREATE INDEX "aiinsight_incident_ai_insights" ON "ai_insights" ("incident_ai_insights");
-- Create index "aiinsight_stage" to table: "ai_insights"
CREATE INDEX "aiinsight_stage" ON "ai_insights" ("stage");
-- Create index "aiinsight_status" to table: "ai_insights"
CREATE INDEX "aiinsight_status" ON "ai_insights" ("status");
-- Create "api_keys" table
CREATE TABLE "api_keys" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
