  PRIMARY KEY ("incident_id", "user_id")
);
-- Create "incidents" table
CREATE TABLE "incidents" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "number" character varying NOT NULL,
  "title" character varying NOT NULL,
  "severity" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'triggered',
  "priority" character varying NOT NULL DEFAULT 'p3',
  "summary" character varying NULL,
  "escalated_count" bigint NOT NULL DEFAULT 0,
  "current_level" bigint NOT NULL DEFAULT 0,
  "merged_into" character varying NULL,
  "trigger_type" character varying NOT NULL DEFAULT 'auto',
  "trigger_source_event_id" character varying NULL,
  "resolved_at" timestamptz NULL,
  "postmortem_skipped" boolean NOT NULL DEFAULT false,
  "acked_at" timestamptz NULL,
  "closed_at" timestamptz NULL,
  "embedding" vector(1536) NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "escalation_policy_incidents" bigint NULL,
  "incident_assignee" bigint NULL,
  "service_incidents" bigint NULL,
  "team_incidents" bigint NULL,
  PRIMARY KEY ("id")
);
-- Create index "incident_resolved_at" to table: "incidents"
CREATE INDEX "incident_resolved_at" ON "incidents" ("resolved_at");
-- Create index "incident_service_incidents" to table: "incidents"
CREATE INDEX "incident_service_incidents" ON "incidents" ("service_incidents");
